-- =========================================================
-- Reemplazo completo de movimientos por los de Julio 2026
-- Ejecutar en: Supabase Dashboard -> SQL Editor -> New query
--
-- Este script:
--   1) Borra TODOS los movimientos existentes (gastos e ingresos)
--   2) Actualiza el saldo inicial del household al saldo de arranque de Julio
--   3) Inserta los 151 movimientos de Julio 2026 tal como figuran en la planilla
--
-- Asume un solo household en la tabla `households` (el caso de esta app).
-- Asume que existe un perfil con display_name = 'Luis' (ajustar si hace falta).
-- =========================================================

begin;

-- 1) Borrar todos los movimientos existentes
delete from movimientos where household_id = (select id from households limit 1);

-- 2) Setear el saldo inicial al de arranque de Julio 2026
update households set saldo_inicial = 84777.26, saldo_inicial_fecha = '2026-07-01'
  where id = (select id from households limit 1);

-- 3) Insertar los movimientos de Julio 2026

commit;